  ('hibiskus', 'Hibiskus', 'Diuretika', 'Furosemid, Hydrochlorothiazid, Torasemid, Spironolacton', 'verstaerkend', '⚠️ Hibiskus selbst diuretisch! Additive Wirkung.', 'MITTEL', '⚠️ Verstärkte Diurese. Elektrolytstörungen möglich (Hypokaliämie).', '⚠️ Elektrolyte kontrollieren! Kaliumspiegel überwachen!', 'Mechanismus'),
  ('hibiskus', 'Hibiskus', 'Antihypertensiva (andere)', 'Amlodipin, Verapamil, Diltiazem, Clonidin', 'verstaerkend', 'Additive blutdrucksenkende Wirkung.', 'MITTEL', '⚠️ Verstärkte Blutdrucksenkung. Hypotonie-Risiko.', '⚠️ Blutdruck engmaschig kontrollieren! Bei Hypotonie Hibiskus reduzieren.', 'Mechanismus'),
