  ('zimt-ceylon', 'Ceylon-Zimt', 'Antidiabetika', 'Metformin, Sulfonylharnstoffe (Glibenclamid, Glimepirid), Insulin, SGLT2-Hemmer, DPP-4-Hemmer', 'verstaerkend', '⚠️ ADDITIV: Meta-Analyse zeigt Nüchternglukose -15 mg/dL. Kann antidiabetische Wirkung verstärken.', 'Moderat', 'Hypoglykämie möglich, besonders bei Sulfonylharnstoffen und Insulin.', '⚠️ Blutzucker häufiger kontrollieren bei Einführung von Zimt. Ggf. Medikamentendosis anpassen.', 'PMID 38917435; Pharmakologie'),
  ('zimt-cassia', 'Cassia-Zimt', 'Vitamin-K-Antagonisten', 'Warfarin (Marcumar, Coumadin), Phenprocoumon', 'verstaerkend', '⛔ CUMARIN-INTERAKTION: Cassia-Zimt enthält Cumarin, das den Vitamin-K-Stoffwechsel hemmt und Antikoagulation verstärkt.', 'Hoch', 'Erhöhte Blutungsneigung, INR-Erhöhung.', '⛔ Cassia-Zimt bei Antikoagulation VERMEIDEN! Ceylon-Zimt verwenden (minimal Cumarin).', 'BfR; Pharmakologie'),
  ('zimt-cassia', 'Cassia-Zimt', 'Hepatotoxische Arzneimittel', 'Paracetamol (hochdosiert), Statine, Amiodaron, Methotrexat, Isoniazid', 'verstaerkend', '⛔ KUMULATIVE HEPATOTOXIZITÄT: Cumarin in Cassia-Zimt ist hepatotoxisch. Kombination erhöht Leberbelastung.', 'Hoch', 'Erhöhte Leberenzyme, Hepatitis.', '⛔ Kombination meiden! Leberwerte kontrollieren. Ceylon-Zimt bevorzugen.', 'BfR; Pharmakologie'),
  ('zimt-ceylon', 'Ceylon-Zimt', 'CYP3A4-Substrate', 'Calciumantagonisten (Amlodipin, Verapamil), Statine (Atorvastatin, Simvastatin), Ciclosporin, Tacrolimus', 'verstaerkend', '⚠️ CYP3A4-HEMMUNG: Zimtaldehyd hemmt CYP3A4 in vitro. Klinische Relevanz bei Supplementdosen unklar.', 'Niedrig-Moderat', 'Möglicherweise erhöhte Plasmaspiegel der Substrate.', '⚠️ Vorsicht bei kritischen CYP3A4-Substraten. Bei Ciclosporin/Tacrolimus: Spiegel überwachen.', 'In-vitro-Studien'),
  ('nelke', 'Gewürznelke', 'Antikoagulantien & Thrombozytenaggregationshemmer', 'Warfarin, ASS, Clopidogrel, Prasugrel, Heparine, DOAKs', 'verstaerkend', '⛔ THROMBOZYTENHEMMUNG: Eugenol hemmt PAF (IC50=7 µM), 5× potenter als Aspirin. Zusätzlich CYP2C9-Hemmung (erhöht Warfarin-Spiegel).', 'Hoch', 'Erhöhte Blutungsneigung. Dokumentierte Fälle.', '⛔ Bei Antikoagulation: Nelken-Supplemente VERMEIDEN! 2 Wochen Karenz vor OP. Als Gewürz minimales Risiko.', 'PMID 2011614; Pharmakologie'),
  ('nelke', 'Gewürznelke', 'Antidiabetika', 'Metformin, Sulfonylharnstoffe, Insulin, Acarbose', 'verstaerkend', '⚠️ ADDITIV: Nelkenextrakt hemmt α-Glucosidase (ähnlich Acarbose). Pilotstudie: 27% postprandiale Glukosereduktion.', 'Niedrig-Moderat', 'Hypoglykämie möglich, besonders mit Acarbose (Wirkmechanismus überlappend).', '⚠️ Blutzucker kontrollieren bei Kombination.', 'PMID 31064377; 24336787'),
  ('nelke', 'Gewürznelke', 'CYP2C9-Substrate', 'Warfarin, NSAIDs (Ibuprofen, Diclofenac), Glibenclamid, Losartan, Torasemid', 'verstaerkend', '⛔ CYP2C9-HEMMUNG: Eugenol hemmt CYP2C9 um 62-68% bei 100 µM. Erhöht Plasmaspiegel der Substrate.', 'Moderat-Hoch', 'Erhöhte NSAID-Toxizität (GI-Blutung). Verstärkte Warfarin-Wirkung.', '⛔ Bei chronischer NSAID-Therapie: Nelken-Supplemente vermeiden. Warfarin: siehe oben.', 'In-vitro-Studie humane Lebermikrosomen'),
  ('nelke', 'Gewürznelke', 'CYP3A4-Substrate', 'Statine, Ca-Blocker, Immunsuppressiva, Makrolide, HIV-Proteaseinhibitoren', 'verstaerkend', '⚠️ CYP3A4-HEMMUNG: Eugenol hemmt CYP3A4 um 67,9% bei 100 µM.', 'Moderat', 'Erhöhte Plasmaspiegel, mehr Nebenwirkungen.', '⚠️ Vorsicht bei kritischen CYP3A4-Substraten.', 'In-vitro-Studie'),
  ('nelke', 'Gewürznelke', 'CYP2D6-Substrate', 'Betablocker (Metoprolol), Antidepressiva (Fluoxetin, Paroxetin), Codein, Tamoxifen', 'verstaerkend', '⚠️ CYP2D6-HEMMUNG: Eugenol hemmt CYP2D6 um 62,7% bei 100 µM.', 'Moderat', 'Veränderte Wirksamkeit/Toxizität. Bei Codein: Weniger Analgesie. Bei Tamoxifen: Weniger Wirksamkeit.', '⚠️ Vorsicht bei Prodrugs (Codein, Tamoxifen). Kombination kann Wirkung verringern.', 'In-vitro-Studie'),
  ('shatavari', 'Shatavari', 'Lithium', 'Lithiumcarbonat, Lithiumcitrat', 'verstaerkend', 'Diuretische Wirkung von Shatavari kann Lithium-Ausscheidung reduzieren -> erhoehte Serumspiegel', 'Mittel', 'Lithium-Toxizitaet moeglich', 'Lithiumspiegel ueberwachen; ggf. Dosis anpassen', 'WebMD; Drugs.com'),
