  ('eleuthero', 'Eleuthero', '⚠️⚠️ Digoxin', 'Digoxin, Digitoxin', 'Assay-Interferenz', '⚠️⚠️ KRITISCH: Eleuthero kann FALSCH-HOHE Digoxin-Spiegel im Labor verursachen (PMID 8705908)! Keine echte pharmakokinetische Interaktion, sondern analytische Interferenz!', '⚠️⚠️ HOCH (diagnostisch)', 'Patient erscheint toxisch ohne Symptome; Fehldiagnose möglich!', '⛔⛔ Bei Digoxin-Therapie: Eleuthero VERMEIDEN oder monoclonale AK-basierte Assays verwenden!', 'McRae 1996 (PMID 8705908)'),
  ('eleuthero', 'Eleuthero', '⚠️ Antikoagulanzien', 'Warfarin, Heparin', 'möglicherweise verstärkend', 'Tierstudien (Li 2015): Erhöhte Warfarin-AUC, verlängerte APTT/PT', '⚠️ Moderat', 'Theoretisch erhöhtes Blutungsrisiko', '⚠️ INR-Monitoring bei Warfarin; Vorsicht!', 'Li et al. 2015; EMA-Monographie'),
  ('eleuthero', 'Eleuthero', 'Immunsuppressiva', 'Ciclosporin, Tacrolimus, Kortikosteroide', 'antagonisierend', 'Eleuthero hat immunmodulatorische Eigenschaften', '⚠️ Moderat', 'Theoretisch Abschwächung der Immunsuppression', '⚠️ Bei Immunsuppression: Eleuthero vermeiden!', 'EMA-Monographie'),
