  ('5-htp', '5-HTP', 'Carbidopa/Levodopa', 'Madopar, Sinemet, Stalevo', 'negativ', '⚠️ Fallbericht: Sklerodermie-aehnliche Erkrankung unter Carbidopa + 5-HTP (PMID: 6997735, NEJM 1980)', 'HOCH', 'Sklerodermie-aehnliche Erkrankung dokumentiert', '⛔ VERMEIDEN!', 'PMID: 6997735, NEJM 1980'),
  ('5-htp', '5-HTP', 'Meperidin/Pethidin', 'Dolantin', 'negativ', 'Meperidin hat serotonerge Aktivitaet', '⛔ KONTRAINDIZIERT', 'Serotonin-Syndrom-Risiko', '⛔ NICHT KOMBINIEREN!', 'Psychopharmacology Institute'),
  ('5-htp', '5-HTP', 'SSRI', 'Sertralin, Fluoxetin, Paroxetin, Citalopram, Escitalopram', 'negativ', '⛔⛔ SEROTONIN-SYNDROM! 5-HTP + SSRI erhöhen beide Serotonin → exzessive serotonerge Aktivität.', '⛔⛔ EXTREM HOCH', 'Hyperthermie, Krampfanfälle, Rhabdomyolyse, Tod möglich!', '⛔⛔ ABSOLUT KONTRAINDIZIERT! 5-HTP NIEMALS mit SSRI!', 'Hunter Criteria, Fachinformationen'),
  ('johanniskraut', 'Johanniskraut', 'SSRI', 'Sertralin, Fluoxetin, Paroxetin, Citalopram', 'negativ', '⛔⛔ SEROTONIN-SYNDROM! Johanniskraut hemmt Serotonin-Wiederaufnahme wie SSRI.', '⛔⛔ EXTREM HOCH', 'Serotonin-Syndrom!', '⛔⛔ ABSOLUT KONTRAINDIZIERT! Johanniskraut NIEMALS mit SSRI!', 'EMA-Monographie, Cochrane'),
  ('johanniskraut', 'Johanniskraut', 'HIV-Medikamente', 'Protease-Inhibitoren, NNRTIs', 'abschwachend', '⛔⛔ CYP3A4-INDUKTION! HIV-Medikamente werden schneller abgebaut.', '⛔⛔ EXTREM HOCH', 'Therapieversagen, virale Resistenz!', '⛔⛔ ABSOLUT KONTRAINDIZIERT!', 'FDA, EMA'),
  ('johanniskraut', 'Johanniskraut', 'Antikoagulanzien', 'Warfarin, Phenprocoumon', 'abschwachend', '⛔⛔ CYP2C9-INDUKTION! Warfarin-Spiegel sinken.', '⛔ HOCH', 'Reduzierte Antikoagulation, Thromboserisiko!', '⛔ KONTRAINDIZIERT! Oder engmaschige INR-Kontrolle.', 'Fachinformationen'),
  ('ashwagandha-angst', 'Ashwagandha', 'Schilddrüsenmedikamente', 'L-Thyroxin, Thiamazol', 'wechselseitig', '⚠️ Ashwagandha kann T3/T4 erhöhen (+19-41%). Destabilisiert Schilddrüseneinstellung.', '⚠️ MITTEL-HOCH', 'Schilddrüsenfunktionsstörung', '⚠️ Bei Schilddrüsenerkrankung: Ashwagandha vermeiden oder engmaschige TSH-Kontrolle!', 'PMID 28829155'),
  ('safran-depression', 'Safran', 'SSRI', 'Sertralin, Fluoxetin', 'neutral', '⚠️ Safran hat serotonerge Wirkung, aber weniger ausgeprägt als 5-HTP. Theoretisches Risiko.', '⚠️ NIEDRIG-MITTEL', 'Theoretisches Serotonin-Syndrom-Risiko', '⚠️ Vorsicht. Besser als 5-HTP, aber nicht völlig risikofrei.', 'Theoretisch, keine schweren Fälle'),
  ('baicalein', 'Baicalein', 'Antikoagulantien (Cumarine)', 'Warfarin (Marcumar/Coumadin), Phenprocoumon', 'verstaerkend', 'Potente kompetitive CYP2C9-Hemmung (Ki <=2,2 mcM). Warfarin wird primaer ueber CYP2C9 metabolisiert. Baicalein erhoet Warfarin-Plasmaspiegel.', 'Hoch', 'Erhoetes Blutungsrisiko! INR-Anstieg moeglich. Potenzierung der gerinnungshemmenden Wirkung.', 'NICHT KOMBINIEREN ohne engmaschige INR-Kontrolle. Patient MUSS Arzt informieren.', 'PMID: 19074529; DrugBank DB16101'),
  ('baicalein', 'Baicalein', 'Antiepileptika', 'Phenytoin (Dilantin), evtl. Tolbutamid', 'verstaerkend', 'CYP2C9-Hemmung erhoet Plasmaspiegel von Phenytoin (CYP2C9-Substrat).', 'Hoch', 'Phenytoin-Toxizitaet moeglich: Nystagmus, Ataxie, Verwirrtheit. Enge therapeutische Breite!', 'NICHT KOMBINIEREN. Phenytoin-Spiegel engmaschig ueberwachen falls unvermeidbar.', 'PMID: 19074529; CYP2C9-Substrat-Profil Phenytoin'),
  ('baicalein', 'Baicalein', 'NSAR (Nicht-steroidale Antirheumatika)', 'Ibuprofen, Diclofenac, Celecoxib, Naproxen', 'verstaerkend', 'CYP2C9-Hemmung kann Plasmaspiegel von CYP2C9-metabolisierten NSAIDs erhoehen. Zusaetzlich: additive COX/LOX-Hemmung.', 'Mittel', 'Erhoetes GI-Blutungsrisiko, erhoete NSAID-Nebenwirkungen (Nieren, GI-Trakt)', 'Vorsicht bei gleichzeitiger Anwendung. Bei Langzeit-NSAID-Therapie: Arzt konsultieren.', 'PMID: 19074529'),
  ('baicalein', 'Baicalein', 'Orale Antidiabetika (Sulfonylharnstoffe)', 'Glipizid, Glimepirid, Tolbutamid', 'verstaerkend', 'CYP2C9-Hemmung erhoet Plasmaspiegel von Sulfonylharnstoffen (CYP2C9-Substrate).', 'Mittel', 'Hypoglykaemie-Risiko durch erhoete Sulfonylharnstoff-Spiegel', 'Blutzucker engmaschig kontrollieren. Arzt informieren.', 'PMID: 19074529'),
  ('baicalein', 'Baicalein', 'Calciumkanalblocker / diverse CYP3A4-Substrate', 'Nimodipin, Tamoxifen, Cyclosporin, Statine (Atorvastatin, Simvastatin)', 'verstaerkend', 'CYP3A4-Hemmung (Rattendaten, Li et al. 2011). Kann Plasmaspiegel von CYP3A4-Substraten erhoehen.', 'Mittel', 'Erhoete Spiegel/Wirkung der betroffenen Medikamente', 'Vorsicht bei Kombination. Arzt informieren.', 'Li et al. 2011; ScienceDirect DOI: 10.1016/j.biopha.2021.111510'),
  ('baicalein', 'Baicalein', 'AT1-Rezeptorblocker (Sartane)', 'Losartan (ueber CYP2C9 aktiviert)', 'abschwachend', 'Losartan ist ein Prodrug, das ueber CYP2C9 zum aktiven Metaboliten E-3174 konvertiert wird. CYP2C9-Hemmung durch Baicalein kann Aktivierung reduzieren.', 'Mittel', 'Verminderte blutdrucksenkende Wirkung von Losartan', 'Alternatives Sartan waehlen (z.B. Valsartan - nicht CYP2C9-abhaengig) oder Arzt konsultieren.', 'PMID: 19074529; Losartan-Metabolismus-Profil'),
  ('gastrodin', 'Gastrodin', 'ZNS-daempfende Medikamente', 'Benzodiazepine (Diazepam, Lorazepam), Barbiturate, Z-Substanzen (Zolpidem)', 'verstaerkend', 'Gastrodin erhoeht GABA-Spiegel und moduliert GABAerge Neurotransmission. Additive ZNS-Daempfung mit anderen GABAergen Substanzen.', 'Mittel', 'Verstaerkte Sedierung, Schlafrigkeit, Atemdepression (theoretisch)', 'Vorsicht bei Kombination. Dosis ggf. anpassen. Arzt konsultieren.', 'PMC12127401; PMC9019412 (GABAerge Modulation dokumentiert)'),
  ('gastrodin', 'Gastrodin', 'Antihypertensiva', 'ACE-Hemmer, Sartane, Calciumkanalblocker, Betablocker', 'verstaerkend', 'Gastrodin hat eigene blutdrucksenkende Wirkung (Meta-Analyse zeigt SBP/DBP-Reduktion). Additive Hypotension moeglich.', 'Niedrig', 'Moeglicherweise verstaerkte Blutdrucksenkung, orthostatische Hypotonie', 'Blutdruck ueberwachen bei Kombination.', 'PMC7337477 (Hypertonie-Meta-Analyse)'),
  ('lentinan', 'Lentinan', 'Immunsuppressiva', 'Cyclosporin, Tacrolimus, Mycophenolat, Azathioprin, Prednisolon (hochdosiert)', 'negativ', 'Lentinan aktiviert Immunsystem (NK-Zellen, T-Zellen, Makrophagen via Dectin-1). Direkt antagonistisch zur immunsuppressiven Therapie.', 'Hoch', 'Transplantat-Abstossung, Schub bei Autoimmunerkrankungen', 'KONTRAINDIZIERT bei Organtransplantation und aktiver Autoimmunerkrankung!', 'PMID: 36619719; PMID: 39245482 (Dectin-1-Mechanismus)'),
  ('lentinan', 'Lentinan', 'Chemotherapeutika (5-FU-basiert)', 'Tegafur, S-1, 5-Fluorouracil, Capecitabin', 'verstaerkend', 'Synergistische Anti-Tumor-Wirkung: Lentinan verstaerkt Immunantwort gegen Tumor + reduziert Chemo-induzierte Immunsuppression.', 'Hoch', 'Verbessertes Gesamtueberleben (IPD-MA: HR 0,80), reduzierte Chemotherapie-Nebenwirkungen', 'Zugelassene Kombination in Japan. NUR unter aerztlicher Aufsicht (Rx).', 'PMID: 19596954 (IPD-Meta-Analyse); PMID: 28940986'),
  ('psk-krestin', 'PSK / Krestin', 'Immunsuppressiva', 'Cyclosporin, Tacrolimus, Mycophenolat, Azathioprin', 'negativ', 'PSK ist TLR2-Agonist und aktiviert dendritische Zellen, T-Zellen, NK-Zellen. Antagonistisch zur Immunsuppression.', 'Hoch', 'Transplantat-Abstossung, Autoimmun-Schub', 'KONTRAINDIZIERT bei Organtransplantation und aktiver Autoimmunerkrankung!', 'PMID: 21068144 (TLR2-Agonist-Mechanismus)'),
  ('psk-krestin', 'PSK / Krestin', 'Chemotherapeutika (diverse)', '5-FU/Tegafur, Mitomycin C, Cyclophosphamid/Doxorubicin (CMF), Cisplatin', 'verstaerkend', 'PSK verstaerkt Anti-Tumor-Immunantwort, reduziert Chemo-induzierte T-Zell-Apoptose und Knochenmarksuppression.', 'Hoch', 'Verlaengertes Gesamtueberleben (MA Magenkrebs HR 0,88; CRC OS-RR 0,71). Reduzierte schwere Nebenwirkungen (RR 0,73).', 'Zugelassene Kombination in Japan (seit 1977). NUR unter aerztlicher Aufsicht.', 'PMID: 17106715; PMID: 16133112; PMID: 28940986')
